import React, { useState, useEffect } from 'react';
import { authAPI, addressAPI, ordersAPI } from '../utils/api';
//import './ProfilePage.css';

const ProfilePage = ({ user, setCurrentPage, profileData, setProfileData, loadOrders, orders }) => {
    const [activeTab, setActiveTab] = useState('profile');
    const [isEditing, setIsEditing] = useState(false);
    const [addresses, setAddresses] = useState([]);
    const [editingAddress, setEditingAddress] = useState(null);
    const [newAddress, setNewAddress] = useState({
        fullName: '',
        phoneNumber: '',
        streetAddress: '',
        city: '',
        state: '',
        postalCode: '',
        country: '',
        isDefault: false
    });
    const [formData, setFormData] = useState({
        fullName: user?.fullName || '',
        email: user?.email || '',
        mobile: user?.mobile || ''
    });
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    useEffect(() => {
        loadAddresses();
        if (activeTab === 'orders') {
            loadOrders();
        }
    }, [activeTab]);

    const loadAddresses = async () => {
        try {
            setLoading(true);
            const response = await addressAPI.getAll();
            setAddresses(response.data || []);
        } catch (error) {
            console.error('Error loading addresses:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleProfileChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleAddressChange = (e) => {
        const { name, value, type, checked } = e.target;
        setNewAddress(prev => ({
            ...prev,
            [name]: type === 'checkbox' ? checked : value
        }));
    };

    const handleAddAddress = async (e) => {
        e.preventDefault();
        try {
            setLoading(true);
            if (editingAddress) {
                await addressAPI.update(editingAddress.id || editingAddress._id, newAddress);
                setMessage('Address updated successfully');
            } else {
                await addressAPI.add(newAddress);
                setMessage('Address added successfully');
            }
            setNewAddress({
                fullName: '',
                phoneNumber: '',
                streetAddress: '',
                city: '',
                state: '',
                postalCode: '',
                country: '',
                isDefault: false
            });
            setEditingAddress(null);
            loadAddresses();
        } catch (error) {
            setMessage('Error saving address');
            console.error('Error:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteAddress = async (id) => {
        if (window.confirm('Are you sure?')) {
            try {
                await addressAPI.remove(id);
                setMessage('Address deleted');
                loadAddresses();
            } catch (error) {
                setMessage('Error deleting address');
            }
        }
    };

    const handleEditAddress = (address) => {
        setNewAddress(address);
        setEditingAddress(address);
    };

    const handleCancelOrder = async (orderId) => {
        if (window.confirm('Cancel this order?')) {
            try {
                await ordersAPI.cancel(orderId);
                setMessage('Order cancelled');
                loadOrders();
            } catch (error) {
                setMessage('Error cancelling order');
            }
        }
    };

    return (
        <div className="profile-page">
            <div className="profile-container">
                <div className="profile-header">
                    <h1>My Account</h1>
                    <p>{user?.email}</p>
                </div>

                <div className="profile-tabs">
                    <button
                        className={`tab ${activeTab === 'profile' ? 'active' : ''}`}
                        onClick={() => setActiveTab('profile')}
                    >
                        Profile
                    </button>
                    <button
                        className={`tab ${activeTab === 'addresses' ? 'active' : ''}`}
                        onClick={() => setActiveTab('addresses')}
                    >
                        Addresses
                    </button>
                    <button
                        className={`tab ${activeTab === 'orders' ? 'active' : ''}`}
                        onClick={() => setActiveTab('orders')}
                    >
                        Orders
                    </button>
                </div>

                {message && <div className="message">{message}</div>}

                {activeTab === 'profile' && (
                    <div className="profile-content">
                        <div className="profile-section">
                            <h2>Personal Information</h2>
                            {!isEditing ? (
                                <div className="profile-info">
                                    <div className="info-item">
                                        <label>Full Name</label>
                                        <p>{formData.fullName}</p>
                                    </div>
                                    <div className="info-item">
                                        <label>Email</label>
                                        <p>{formData.email}</p>
                                    </div>
                                    <div className="info-item">
                                        <label>Mobile</label>
                                        <p>{formData.mobile}</p>
                                    </div>
                                    <button className="btn-edit" onClick={() => setIsEditing(true)}>
                                        Edit Profile
                                    </button>
                                </div>
                            ) : (
                                <form className="profile-form">
                                    <input
                                        type="text"
                                        name="fullName"
                                        value={formData.fullName}
                                        onChange={handleProfileChange}
                                        placeholder="Full Name"
                                    />
                                    <input
                                        type="email"
                                        name="email"
                                        value={formData.email}
                                        onChange={handleProfileChange}
                                        placeholder="Email"
                                        disabled
                                    />
                                    <input
                                        type="tel"
                                        name="mobile"
                                        value={formData.mobile}
                                        onChange={handleProfileChange}
                                        placeholder="Mobile"
                                    />
                                    <div className="form-actions">
                                        <button type="button" className="btn-save" onClick={() => setIsEditing(false)}>
                                            Save Changes
                                        </button>
                                        <button type="button" className="btn-cancel" onClick={() => setIsEditing(false)}>
                                            Cancel
                                        </button>
                                    </div>
                                </form>
                            )}
                        </div>
                    </div>
                )}

                {activeTab === 'addresses' && (
                    <div className="addresses-content">
                        <div className="addresses-list">
                            <h2>Saved Addresses</h2>
                            {addresses.length > 0 ? (
                                <div className="address-cards">
                                    {addresses.map((addr) => (
                                        <div key={addr.id || addr._id} className="address-card">
                                            <h4>{addr.fullName}</h4>
                                            <p>{addr.streetAddress}, {addr.city}</p>
                                            <p>{addr.state} {addr.postalCode}, {addr.country}</p>
                                            <p>📱 {addr.phoneNumber}</p>
                                            {addr.isDefault && <span className="badge-default">Default</span>}
                                            <div className="address-actions">
                                                <button
                                                    className="btn-edit"
                                                    onClick={() => handleEditAddress(addr)}
                                                >
                                                    Edit
                                                </button>
                                                <button
                                                    className="btn-delete"
                                                    onClick={() => handleDeleteAddress(addr.id || addr._id)}
                                                >
                                                    Delete
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <p>No addresses saved yet</p>
                            )}
                        </div>

                        <div className="add-address-form">
                            <h3>{editingAddress ? 'Edit Address' : 'Add New Address'}</h3>
                            <form onSubmit={handleAddAddress}>
                                <input
                                    type="text"
                                    name="fullName"
                                    value={newAddress.fullName}
                                    onChange={handleAddressChange}
                                    placeholder="Full Name"
                                    required
                                />
                                <input
                                    type="tel"
                                    name="phoneNumber"
                                    value={newAddress.phoneNumber}
                                    onChange={handleAddressChange}
                                    placeholder="Phone Number"
                                    required
                                />
                                <input
                                    type="text"
                                    name="streetAddress"
                                    value={newAddress.streetAddress}
                                    onChange={handleAddressChange}
                                    placeholder="Street Address"
                                    required
                                />
                                <div className="form-row">
                                    <input
                                        type="text"
                                        name="city"
                                        value={newAddress.city}
                                        onChange={handleAddressChange}
                                        placeholder="City"
                                        required
                                    />
                                    <input
                                        type="text"
                                        name="state"
                                        value={newAddress.state}
                                        onChange={handleAddressChange}
                                        placeholder="State"
                                        required
                                    />
                                </div>
                                <div className="form-row">
                                    <input
                                        type="text"
                                        name="postalCode"
                                        value={newAddress.postalCode}
                                        onChange={handleAddressChange}
                                        placeholder="Postal Code"
                                        required
                                    />
                                    <input
                                        type="text"
                                        name="country"
                                        value={newAddress.country}
                                        onChange={handleAddressChange}
                                        placeholder="Country"
                                        required
                                    />
                                </div>
                                <label className="checkbox">
                                    <input
                                        type="checkbox"
                                        name="isDefault"
                                        checked={newAddress.isDefault}
                                        onChange={handleAddressChange}
                                    />
                                    Set as default address
                                </label>
                                <button type="submit" className="btn-save" disabled={loading}>
                                    {loading ? 'Saving...' : editingAddress ? 'Update Address' : 'Add Address'}
                                </button>
                                {editingAddress && (
                                    <button
                                        type="button"
                                        className="btn-cancel"
                                        onClick={() => {
                                            setEditingAddress(null);
                                            setNewAddress({
                                                fullName: '',
                                                phoneNumber: '',
                                                streetAddress: '',
                                                city: '',
                                                state: '',
                                                postalCode: '',
                                                country: '',
                                                isDefault: false
                                            });
                                        }}
                                    >
                                        Cancel
                                    </button>
                                )}
                            </form>
                        </div>
                    </div>
                )}

                {activeTab === 'orders' && (
                    <div className="orders-content">
                        <h2>My Orders</h2>
                        {orders && orders.length > 0 ? (
                            <div className="orders-list">
                                {orders.map((order) => (
                                    <div key={order._id || order.id} className="order-card">
                                        <div className="order-header">
                                            <div>
                                                <h4>Order #{order.orderNumber}</h4>
                                                <p className="order-date">
                                                    {new Date(order.createdAt).toLocaleDateString()}
                                                </p>
                                            </div>
                                            <span className={`status ${order.status?.toLowerCase()}`}>
                                                {order.status}
                                            </span>
                                        </div>
                                        <div className="order-details">
                                            <p>₹ <strong>{order.totalPrice}</strong></p>
                                            <p>{order.items?.length} item(s)</p>
                                        </div>
                                        <div className="order-actions">
                                            <button className="btn-view">View Details</button>
                                            {order.status === 'Pending' && (
                                                <button
                                                    className="btn-cancel"
                                                    onClick={() => handleCancelOrder(order._id || order.id)}
                                                >
                                                    Cancel Order
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <p>No orders yet</p>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

export default ProfilePage;
